16	/**
17	 * DynamoDB JSON protocol handler.
18	 * Called by {@link AwsJsonController} for DynamoDB-targeted requests.
19	 */
20	@ApplicationScoped
21	public class DynamoDbJsonHandler {
22	
23	    private final DynamoDbService dynamoDbService;
24	    private final DynamoDbStreamService dynamoDbStreamService;
25	    private final ObjectMapper objectMapper;
26	
27	    @Inject
28	    public DynamoDbJsonHandler(DynamoDbService dynamoDbService, DynamoDbStreamService dynamoDbStreamService,
29	                               ObjectMapper objectMapper) {
30	        this.dynamoDbService = dynamoDbService;
31	        this.dynamoDbStreamService = dynamoDbStreamService;
32	        this.objectMapper = objectMapper;
33	    }
