64	    private Response handleCreateTable(JsonNode request, String region) {
65	        String tableName = request.path("TableName").asText();
66	
67	        List<KeySchemaElement> keySchema = new ArrayList<>();
68	        request.path("KeySchema").forEach(ks ->
69	                keySchema.add(new KeySchemaElement(
70	                        ks.path("AttributeName").asText(),
71	                        ks.path("KeyType").asText())));
72	
73	        List<AttributeDefinition> attrDefs = new ArrayList<>();
74	        request.path("AttributeDefinitions").forEach(ad ->
75	                attrDefs.add(new AttributeDefinition(
76	                        ad.path("AttributeName").asText(),
77	                        ad.path("AttributeType").asText())));
78	
79	        Long readCapacity = null;
80	        Long writeCapacity = null;
81	        JsonNode pt = request.path("ProvisionedThroughput");
82	        if (!pt.isMissingNode()) {
83	            readCapacity = pt.path("ReadCapacityUnits").asLong(5);
84	            writeCapacity = pt.path("WriteCapacityUnits").asLong(5);
85	        }
86	
87	        List<GlobalSecondaryIndex> gsis = new ArrayList<>();
88	        JsonNode gsiArray = request.path("GlobalSecondaryIndexes");
89	        if (!gsiArray.isMissingNode() && gsiArray.isArray()) {
90	            for (JsonNode gsiNode : gsiArray) {
91	                String indexName = gsiNode.path("IndexName").asText();
92	                List<KeySchemaElement> gsiKeySchema = new ArrayList<>();
93	                gsiNode.path("KeySchema").forEach(ks ->
94	                        gsiKeySchema.add(new KeySchemaElement(
95	                                ks.path("AttributeName").asText(),
96	                                ks.path("KeyType").asText())));
97	                String projectionType = gsiNode.path("Projection").path("ProjectionType").asText("ALL");
98	                JsonNode nonKeyAttrArray = gsiNode.path("Projection").path("NonKeyAttributes");
99	                List<String> nonKeyAttributes = new ArrayList<>();
100	                if (!nonKeyAttrArray.isMissingNode() && nonKeyAttrArray.isArray()){
101	                    for (JsonNode nonKeyAttr : nonKeyAttrArray){
102	                        nonKeyAttributes.add(nonKeyAttr.asText());
103	                    }
104	                }
105	                GlobalSecondaryIndex gsi = new GlobalSecondaryIndex(indexName, gsiKeySchema, null, projectionType, nonKeyAttributes);
106	                JsonNode gsiPt = gsiNode.path("ProvisionedThroughput");
107	                if (!gsiPt.isMissingNode()) {
108	                    gsi.getProvisionedThroughput().setReadCapacityUnits(gsiPt.path("ReadCapacityUnits").asLong(0));
109	                    gsi.getProvisionedThroughput().setWriteCapacityUnits(gsiPt.path("WriteCapacityUnits").asLong(0));
110	                }
111	                gsis.add(gsi);
112	            }
113	        }
114	
115	        List<LocalSecondaryIndex> lsis = new ArrayList<>();
116	        JsonNode lsiArray = request.path("LocalSecondaryIndexes");
117	        if (!lsiArray.isMissingNode() && lsiArray.isArray()) {
118	            for (JsonNode lsiNode : lsiArray) {
119	                String indexName = lsiNode.path("IndexName").asText();
120	                List<KeySchemaElement> lsiKeySchema = new ArrayList<>();
121	                lsiNode.path("KeySchema").forEach(ks ->
122	                        lsiKeySchema.add(new KeySchemaElement(
123	                                ks.path("AttributeName").asText(),
124	                                ks.path("KeyType").asText())));
125	                String projectionType = lsiNode.path("Projection").path("ProjectionType").asText("ALL");
126	                lsis.add(new LocalSecondaryIndex(indexName, lsiKeySchema, null, projectionType));
127	            }
128	        }
129	
130	        String billingMode = request.has("BillingMode")
131	                ? request.get("BillingMode").asText() : null;
132	
133	        TableDefinition table = dynamoDbService.createTable(tableName, keySchema, attrDefs,
134	                readCapacity, writeCapacity, gsis, lsis, region);
135	
136	        if ("PAY_PER_REQUEST".equals(billingMode)) {
137	            table.setBillingMode("PAY_PER_REQUEST");
138	            table.getProvisionedThroughput().setReadCapacityUnits(0L);
139	            table.getProvisionedThroughput().setWriteCapacityUnits(0L);
140	        } else {
141	            table.setBillingMode("PROVISIONED");
142	        }
143	
144	        // Store tags from CreateTable request
145	        JsonNode tagsNode = request.path("Tags");
146	        if (tagsNode.isArray()) {
147	            for (JsonNode tag : tagsNode) {
148	                table.getTags().put(tag.path("Key").asText(), tag.path("Value").asText());
149	            }
150	        }
151	
152	        JsonNode streamSpec = request.path("StreamSpecification");
153	        if (!streamSpec.isMissingNode() && streamSpec.path("StreamEnabled").asBoolean(false)) {
154	            String viewType = streamSpec.path("StreamViewType").asText("NEW_AND_OLD_IMAGES");
155	            StreamDescription sd = dynamoDbStreamService.enableStream(
156	                    tableName, table.getTableArn(), viewType, region);
157	            table.setStreamEnabled(true);
158	            table.setStreamArn(sd.getStreamArn());
159	            table.setStreamViewType(viewType);
160	        }
161	
162	        ObjectNode response = objectMapper.createObjectNode();
163	        response.set("TableDescription", tableToNode(table));
164	        return Response.ok(response).build();
165	    }
