167	    private Response handleDeleteTable(JsonNode request, String region) {
168	        String tableName = request.path("TableName").asText();
169	        TableDefinition table = dynamoDbService.describeTable(tableName, region);
170	        dynamoDbService.deleteTable(tableName, region);
171	
172	        table.setTableStatus("DELETING");
173	        ObjectNode response = objectMapper.createObjectNode();
174	        response.set("TableDescription", tableToNode(table));
175	        return Response.ok(response).build();
176	    }
