197	    private Response handlePutItem(JsonNode request, String region) {
198	        String tableName = request.path("TableName").asText();
199	        JsonNode item = request.path("Item");
200	        String returnValues = request.path("ReturnValues").asText("NONE");
201	        String conditionExpression = request.has("ConditionExpression")
202	                ? request.get("ConditionExpression").asText() : null;
203	        JsonNode exprAttrNames = request.has("ExpressionAttributeNames")
204	                ? request.get("ExpressionAttributeNames") : null;
205	        JsonNode exprAttrValues = request.has("ExpressionAttributeValues")
206	                ? request.get("ExpressionAttributeValues") : null;
207	
208	        JsonNode oldItem = null;
209	        if ("ALL_OLD" .equals(returnValues)) {
210	            dynamoDbService.describeTable(tableName, region);
211	            oldItem = dynamoDbService.getItem(tableName, item, region);
212	        }
213	
214	        dynamoDbService.putItem(tableName, item, conditionExpression, exprAttrNames, exprAttrValues, region);
215	
216	        ObjectNode response = objectMapper.createObjectNode();
217	        if ("ALL_OLD" .equals(returnValues) && oldItem != null) {
218	            response.set("Attributes", oldItem);
219	        }
220	        return Response.ok(response).build();
221	    }
