286	    private Response handleQuery(JsonNode request, String region) {
287	        String tableName = request.path("TableName").asText();
288	        JsonNode keyConditions = request.has("KeyConditions") ? request.get("KeyConditions") : null;
289	        JsonNode exprAttrValues = request.has("ExpressionAttributeValues")
290	                ? request.get("ExpressionAttributeValues") : null;
291	        JsonNode exprAttrNames = request.has("ExpressionAttributeNames")
292	                ? request.get("ExpressionAttributeNames") : null;
293	        String keyConditionExpr = request.has("KeyConditionExpression")
294	                ? request.get("KeyConditionExpression").asText() : null;
295	        String filterExpr = request.has("FilterExpression")
296	                ? request.get("FilterExpression").asText() : null;
297	        Integer limit = request.has("Limit") ? request.get("Limit").asInt() : null;
298	        Boolean scanIndexForward = request.has("ScanIndexForward")
299	                ? request.get("ScanIndexForward").asBoolean() : null;
300	        String indexName = request.has("IndexName") ? request.get("IndexName").asText() : null;
301	        JsonNode exclusiveStartKey = request.has("ExclusiveStartKey")
302	                ? request.get("ExclusiveStartKey") : null;
303	
304	        DynamoDbService.QueryResult result = dynamoDbService.query(tableName, keyConditions,
305	                exprAttrValues, keyConditionExpr, filterExpr, limit, scanIndexForward, indexName,
306	                exclusiveStartKey, exprAttrNames, region);
307	
308	        ObjectNode response = objectMapper.createObjectNode();
309	        ArrayNode itemsArray = objectMapper.createArrayNode();
310	        result.items().forEach(itemsArray::add);
311	        response.set("Items", itemsArray);
312	        response.put("Count", result.items().size());
313	        response.put("ScannedCount", result.scannedCount());
314	        if (result.lastEvaluatedKey() != null) {
315	            response.set("LastEvaluatedKey", result.lastEvaluatedKey());
316	        }
317	        return Response.ok(response).build();
318	    }
