349	    private Response handleBatchWriteItem(JsonNode request, String region) {
350	        JsonNode requestItems = request.get("RequestItems");
351	        if (requestItems == null || requestItems.isNull() || requestItems.isMissingNode()) {
352	            return Response.ok(objectMapper.createObjectNode()
353	                    .set("UnprocessedItems", objectMapper.createObjectNode())).build();
354	        }
355	        Map<String, List<JsonNode>> items = new HashMap<>();
356	        Iterator<Map.Entry<String, JsonNode>> tables = requestItems.fields();
357	        while (tables.hasNext()) {
358	            var entry = tables.next();
359	            List<JsonNode> writes = new ArrayList<>();
360	            for (JsonNode writeReq : entry.getValue()) {
361	                writes.add(writeReq);
362	            }
363	            items.put(entry.getKey(), writes);
364	        }
365	
366	        dynamoDbService.batchWriteItem(items, region);
367	
368	        ObjectNode response = objectMapper.createObjectNode();
369	        response.set("UnprocessedItems", objectMapper.createObjectNode());
370	        return Response.ok(response).build();
371	    }
