373	    private Response handleBatchGetItem(JsonNode request, String region) {
374	        JsonNode requestItems = request.get("RequestItems");
375	        if (requestItems == null || requestItems.isNull() || requestItems.isMissingNode()) {
376	            ObjectNode response = objectMapper.createObjectNode();
377	            response.set("Responses", objectMapper.createObjectNode());
378	            response.set("UnprocessedKeys", objectMapper.createObjectNode());
379	            return Response.ok(response).build();
380	        }
381	        Map<String, JsonNode> items = new HashMap<>();
382	        Iterator<Map.Entry<String, JsonNode>> tables = requestItems.fields();
383	        while (tables.hasNext()) {
384	            var entry = tables.next();
385	            items.put(entry.getKey(), entry.getValue());
386	        }
387	
388	        DynamoDbService.BatchGetResult result = dynamoDbService.batchGetItem(items, region);
389	
390	        ObjectNode response = objectMapper.createObjectNode();
391	        ObjectNode responses = objectMapper.createObjectNode();
392	        for (Map.Entry<String, List<JsonNode>> entry : result.responses().entrySet()) {
393	            ArrayNode tableItems = objectMapper.createArrayNode();
394	            entry.getValue().forEach(tableItems::add);
395	            responses.set(entry.getKey(), tableItems);
396	        }
397	        response.set("Responses", responses);
398	        response.set("UnprocessedKeys", objectMapper.createObjectNode());
399	        return Response.ok(response).build();
400	    }
