402	    private Response handleUpdateTable(JsonNode request, String region) {
403	        String tableName = request.path("TableName").asText();
404	        Long readCapacity = null;
405	        Long writeCapacity = null;
406	        JsonNode pt = request.path("ProvisionedThroughput");
407	        if (!pt.isMissingNode()) {
408	            readCapacity = pt.has("ReadCapacityUnits") ? pt.get("ReadCapacityUnits").asLong() : null;
409	            writeCapacity = pt.has("WriteCapacityUnits") ? pt.get("WriteCapacityUnits").asLong() : null;
410	        }
411	
412	        List<GlobalSecondaryIndex> gsiCreates = new ArrayList<>();
413	        List<String> gsiDeletes = new ArrayList<>();
414	        JsonNode gsiUpdates = request.path("GlobalSecondaryIndexUpdates");
415	        if (!gsiUpdates.isMissingNode() && gsiUpdates.isArray()) {
416	            for (JsonNode update : gsiUpdates) {
417	                JsonNode createNode = update.path("Create");
418	                if (!createNode.isMissingNode()) {
419	                    String indexName = createNode.path("IndexName").asText();
420	                    List<KeySchemaElement> gsiKeySchema = new ArrayList<>();
421	                    createNode.path("KeySchema").forEach(ks ->
422	                            gsiKeySchema.add(new KeySchemaElement(
423	                                    ks.path("AttributeName").asText(),
424	                                    ks.path("KeyType").asText())));
425	                    String projectionType = createNode.path("Projection").path("ProjectionType").asText("ALL");
426	                    JsonNode nonKeyAttrArray = createNode.path("Projection").path("NonKeyAttributes");
427	                    List<String> nonKeyAttributes = new ArrayList<>();
428	                    if (!nonKeyAttrArray.isMissingNode() && nonKeyAttrArray.isArray()){
429	                        for (JsonNode nonKeyAttr : nonKeyAttrArray){
430	                            nonKeyAttributes.add(nonKeyAttr.asText());
431	                        }
432	                    }
433	                    GlobalSecondaryIndex newGsi = new GlobalSecondaryIndex(indexName, gsiKeySchema, null, projectionType, nonKeyAttributes);
434	                    JsonNode newGsiPt = createNode.path("ProvisionedThroughput");
435	                    if (!newGsiPt.isMissingNode()) {
436	                        newGsi.getProvisionedThroughput().setReadCapacityUnits(newGsiPt.path("ReadCapacityUnits").asLong(0));
437	                        newGsi.getProvisionedThroughput().setWriteCapacityUnits(newGsiPt.path("WriteCapacityUnits").asLong(0));
438	                    }
439	                    gsiCreates.add(newGsi);
440	                }
441	                JsonNode deleteNode = update.path("Delete");
442	                if (!deleteNode.isMissingNode()) {
443	                    gsiDeletes.add(deleteNode.path("IndexName").asText());
444	                }
445	            }
446	        }
447	
448	        List<AttributeDefinition> newAttrDefs = new ArrayList<>();
449	        JsonNode attrDefsNode = request.path("AttributeDefinitions");
450	        if (!attrDefsNode.isMissingNode() && attrDefsNode.isArray()) {
451	            for (JsonNode ad : attrDefsNode) {
452	                newAttrDefs.add(new AttributeDefinition(
453	                        ad.path("AttributeName").asText(),
454	                        ad.path("AttributeType").asText()));
455	            }
456	        }
457	
458	        TableDefinition table = dynamoDbService.updateTable(tableName, readCapacity, writeCapacity,
459	                gsiCreates, gsiDeletes, newAttrDefs, region);
460	
461	        String billingMode = request.has("BillingMode")
462	                ? request.get("BillingMode").asText() : null;
463	        if (billingMode != null) {
464	            table.setBillingMode(billingMode);
465	            if ("PAY_PER_REQUEST".equals(billingMode)) {
466	                table.getProvisionedThroughput().setReadCapacityUnits(0L);
467	                table.getProvisionedThroughput().setWriteCapacityUnits(0L);
468	            }
469	        }
470	
471	        JsonNode streamSpec = request.path("StreamSpecification");
472	        if (!streamSpec.isMissingNode()) {
473	            boolean streamEnabled = streamSpec.path("StreamEnabled").asBoolean(false);
474	            if (streamEnabled) {
475	                String viewType = streamSpec.path("StreamViewType").asText("NEW_AND_OLD_IMAGES");
476	                StreamDescription sd = dynamoDbStreamService.enableStream(
477	                        tableName, table.getTableArn(), viewType, region);
478	                table.setStreamEnabled(true);
479	                table.setStreamArn(sd.getStreamArn());
480	                table.setStreamViewType(viewType);
481	            } else {
482	                dynamoDbStreamService.disableStream(tableName, region);
483	                table.setStreamEnabled(false);
484	            }
485	        }
486	
487	        ObjectNode response = objectMapper.createObjectNode();
488	        response.set("TableDescription", tableToNode(table));
489	        return Response.ok(response).build();
490	    }
