492	    private Response handleDescribeTimeToLive(JsonNode request, String region) {
493	        String tableName = request.path("TableName").asText();
494	        TableDefinition table = dynamoDbService.describeTable(tableName, region);
495	
496	        ObjectNode response = objectMapper.createObjectNode();
497	        ObjectNode ttlDesc = objectMapper.createObjectNode();
498	        if (table.isTtlEnabled() && table.getTtlAttributeName() != null) {
499	            ttlDesc.put("TimeToLiveStatus", "ENABLED");
500	            ttlDesc.put("AttributeName", table.getTtlAttributeName());
501	        } else {
502	            ttlDesc.put("TimeToLiveStatus", "DISABLED");
503	        }
504	        response.set("TimeToLiveDescription", ttlDesc);
505	        return Response.ok(response).build();
506	    }
