508	    private Response handleUpdateTimeToLive(JsonNode request, String region) {
509	        String tableName = request.path("TableName").asText();
510	        JsonNode spec = request.path("TimeToLiveSpecification");
511	        String ttlAttributeName = spec.path("AttributeName").asText();
512	        boolean enabled = spec.path("Enabled").asBoolean(false);
513	
514	        dynamoDbService.updateTimeToLive(tableName, ttlAttributeName, enabled, region);
515	
516	        ObjectNode response = objectMapper.createObjectNode();
517	        ObjectNode ttlSpec = objectMapper.createObjectNode();
518	        ttlSpec.put("AttributeName", ttlAttributeName);
519	        ttlSpec.put("Enabled", enabled);
520	        response.set("TimeToLiveSpecification", ttlSpec);
521	        return Response.ok(response).build();
522	    }
