524	    private Response handleTransactWriteItems(JsonNode request, String region) {
525	        JsonNode transactItemsNode = request.path("TransactItems");
526	        List<JsonNode> transactItems = new ArrayList<>();
527	        if (transactItemsNode.isArray()) {
528	            transactItemsNode.forEach(transactItems::add);
529	        }
530	
531	        try {
532	            dynamoDbService.transactWriteItems(transactItems, region);
533	            return Response.ok(objectMapper.createObjectNode()).build();
534	        } catch (TransactionCanceledException e) {
535	            ObjectNode body = objectMapper.createObjectNode();
536	            body.put("__type", "TransactionCanceledException");
537	            body.put("message", e.getMessage());
538	            ArrayNode reasons = body.putArray("CancellationReasons");
539	            for (String reason : e.getCancellationReasons()) {
540	                ObjectNode r = objectMapper.createObjectNode();
541	                r.put("Code", reason.isEmpty() ? "None" : "ConditionalCheckFailed");
542	                r.put("Message", reason);
543	                reasons.add(r);
544	            }
545	            return Response.status(400).entity(body).build();
546	        }
547	    }
