613	    private ObjectNode tableToNode(TableDefinition table) {
614	        ObjectNode node = objectMapper.createObjectNode();
615	        node.put("TableName", table.getTableName());
616	        node.put("TableStatus", table.getTableStatus());
617	        node.put("TableArn", table.getTableArn());
618	        node.put("CreationDateTime", table.getCreationDateTime().getEpochSecond());
619	        node.put("ItemCount", table.getItemCount());
620	        node.put("TableSizeBytes", table.getTableSizeBytes());
621	        node.put("DeletionProtectionEnabled", false);
622	
623	        if ("PAY_PER_REQUEST".equals(table.getBillingMode())) {
624	            ObjectNode billing = objectMapper.createObjectNode();
625	            billing.put("BillingMode", "PAY_PER_REQUEST");
626	            billing.put("LastUpdateToPayPerRequestDateTime",
627	                    table.getCreationDateTime().getEpochSecond());
628	            node.set("BillingModeSummary", billing);
629	        }
630	
631	        ObjectNode warmThroughput = objectMapper.createObjectNode();
632	        warmThroughput.put("Status", "ACTIVE");
633	        warmThroughput.put("ReadUnitsPerSecond", 0);
634	        warmThroughput.put("WriteUnitsPerSecond", 0);
635	        node.set("WarmThroughput", warmThroughput);
636	
637	        ArrayNode keySchemaArray = objectMapper.createArrayNode();
638	        for (var ks : table.getKeySchema()) {
639	            ObjectNode ksNode = objectMapper.createObjectNode();
640	            ksNode.put("AttributeName", ks.getAttributeName());
641	            ksNode.put("KeyType", ks.getKeyType());
642	            keySchemaArray.add(ksNode);
643	        }
644	        node.set("KeySchema", keySchemaArray);
645	
646	        ArrayNode attrDefsArray = objectMapper.createArrayNode();
647	        for (var ad : table.getAttributeDefinitions()) {
648	            ObjectNode adNode = objectMapper.createObjectNode();
649	            adNode.put("AttributeName", ad.getAttributeName());
650	            adNode.put("AttributeType", ad.getAttributeType());
651	            attrDefsArray.add(adNode);
652	        }
653	        node.set("AttributeDefinitions", attrDefsArray);
654	
655	        ObjectNode ptNode = objectMapper.createObjectNode();
656	        ptNode.put("ReadCapacityUnits", table.getProvisionedThroughput().getReadCapacityUnits());
657	        ptNode.put("WriteCapacityUnits", table.getProvisionedThroughput().getWriteCapacityUnits());
658	        ptNode.put("NumberOfDecreasesToday", table.getProvisionedThroughput().getNumberOfDecreasesToday());
659	        node.set("ProvisionedThroughput", ptNode);
660	
661	        List<GlobalSecondaryIndex> gsis = table.getGlobalSecondaryIndexes();
662	        if (gsis != null && !gsis.isEmpty()) {
663	            ArrayNode gsiArray = objectMapper.createArrayNode();
664	            for (GlobalSecondaryIndex gsi : gsis) {
665	                ObjectNode gsiNode = objectMapper.createObjectNode();
666	                gsiNode.put("IndexName", gsi.getIndexName());
667	                gsiNode.put("IndexArn", gsi.getIndexArn());
668	                gsiNode.put("IndexStatus", "ACTIVE");
669	
670	                ArrayNode gsiKeySchema = objectMapper.createArrayNode();
671	                for (var ks : gsi.getKeySchema()) {
672	                    ObjectNode ksNode = objectMapper.createObjectNode();
673	                    ksNode.put("AttributeName", ks.getAttributeName());
674	                    ksNode.put("KeyType", ks.getKeyType());
675	                    gsiKeySchema.add(ksNode);
676	                }
677	                gsiNode.set("KeySchema", gsiKeySchema);
678	
679	                ObjectNode projection = objectMapper.createObjectNode();
680	                projection.put("ProjectionType",
681	                        gsi.getProjectionType() != null ? gsi.getProjectionType() : "ALL");
682	                if ("INCLUDE".equals(gsi.getProjectionType())){
683	                    ArrayNode nonKeyAttributes = objectMapper.createArrayNode();
684	                    for (var attr : gsi.getNonKeyAttributes()){
685	                        nonKeyAttributes.add(attr);
686	                    }
687	                    projection.put("NonKeyAttributes", nonKeyAttributes);
688	                }
689	                gsiNode.set("Projection", projection);
690	
691	                ObjectNode gsiPt = objectMapper.createObjectNode();
692	                gsiPt.put("ReadCapacityUnits", gsi.getProvisionedThroughput().getReadCapacityUnits());
693	                gsiPt.put("WriteCapacityUnits", gsi.getProvisionedThroughput().getWriteCapacityUnits());
694	                gsiPt.put("NumberOfDecreasesToday", gsi.getProvisionedThroughput().getNumberOfDecreasesToday());
695	                gsiNode.set("ProvisionedThroughput", gsiPt);
696	                gsiNode.put("IndexSizeBytes", gsi.getIndexSizeBytes());
697	                gsiNode.put("ItemCount", gsi.getItemCount());
698	
699	                gsiArray.add(gsiNode);
700	            }
701	            node.set("GlobalSecondaryIndexes", gsiArray);
702	        }
703	
704	        List<LocalSecondaryIndex> lsis = table.getLocalSecondaryIndexes();
705	        if (lsis != null && !lsis.isEmpty()) {
706	            ArrayNode lsiArray = objectMapper.createArrayNode();
707	            for (LocalSecondaryIndex lsi : lsis) {
708	                ObjectNode lsiNode = objectMapper.createObjectNode();
709	                lsiNode.put("IndexName", lsi.getIndexName());
710	                lsiNode.put("IndexArn", lsi.getIndexArn());
711	
712	                ArrayNode lsiKeySchema = objectMapper.createArrayNode();
