714	                    ObjectNode ksNode = objectMapper.createObjectNode();
715	                    ksNode.put("AttributeName", ks.getAttributeName());
716	                    ksNode.put("KeyType", ks.getKeyType());
717	                    lsiKeySchema.add(ksNode);
718	                }
719	                lsiNode.set("KeySchema", lsiKeySchema);
720	
721	                ObjectNode projection = objectMapper.createObjectNode();
722	                projection.put("ProjectionType",
723	                        lsi.getProjectionType() != null ? lsi.getProjectionType() : "ALL");
724	                lsiNode.set("Projection", projection);
725	
