1005	    private String applyRemoveClause(ObjectNode item, String clause, JsonNode exprAttrNames) {
1006	        while (!clause.isEmpty()) {
1007	            String upper = clause.toUpperCase();
1008	            if (upper.startsWith("SET ") || upper.startsWith("ADD ") || upper.startsWith("DELETE ")) {
1009	                break;
1010	            }
1011	
1012	            int commaIdx = findNextComma(clause);
1013	            String attrPart;
1014	            if (commaIdx >= 0) {
1015	                attrPart = clause.substring(0, commaIdx).trim();
1016	                clause = clause.substring(commaIdx + 1).trim();
1017	            } else {
1018	                int nextClause = findNextClauseKeyword(clause);
1019	                if (nextClause >= 0) {
1020	                    attrPart = clause.substring(0, nextClause).trim();
1021	                    clause = clause.substring(nextClause).trim();
1022	                } else {
1023	                    attrPart = clause.trim();
1024	                    clause = "";
1025	                }
1026	            }
1027	
1028	            String attrName = resolveAttributeName(attrPart, exprAttrNames);
1029	            item.remove(attrName);
1030	        }
1031	        return clause;
1032	    }
