1189	    // --- Filter expression evaluation ---
1190	
1191	    private boolean matchesFilterExpression(JsonNode item, String filterExpression,
1192	                                             JsonNode exprAttrNames, JsonNode exprAttrValues) {
1193	        filterExpression = trimBalancedOuterParens(filterExpression);
1194	        // Handle AND/OR combined expressions
1195	        // Split on AND first (simple approach — handles most common cases)
1196	        String[] andParts = filterExpression.split("\\s+[Aa][Nn][Dd]\\s+");
1197	        for (String part : andParts) {
1198	            if (!evaluateSingleCondition(item, part.trim(), exprAttrNames, exprAttrValues)) {
1199	                return false;
1200	            }
1201	        }
1202	        return true;
1203	    }
