1205	    private boolean evaluateSingleCondition(JsonNode item, String condition,
1206	                                             JsonNode exprAttrNames, JsonNode exprAttrValues) {
1207	        condition = trimBalancedOuterParens(condition);
1208	        // Parse: "attrPath = :val", "attrPath <> :val", "attrPath > :val", etc.
1209	        // Also: "attribute_exists(attrPath)", "attribute_not_exists(attrPath)",
1210	        //        "begins_with(attrPath, :val)", "contains(attrPath, :val)"
1211	        String condLower = condition.toLowerCase();
1212	
1213	        if (condLower.startsWith("attribute_exists")) {
1214	            String attr = extractFunctionArg(condition);
1215	            String resolvedPath = resolveAttributePath(attr, exprAttrNames);
1216	            return item != null && resolveNestedAttribute(item, resolvedPath) != null;
1217	        }
1218	        if (condLower.startsWith("attribute_not_exists")) {
1219	            String attr = extractFunctionArg(condition);
1220	            String resolvedPath = resolveAttributePath(attr, exprAttrNames);
1221	            return item == null || resolveNestedAttribute(item, resolvedPath) == null;
1222	        }
1223	        if (condLower.startsWith("begins_with")) {
1224	            String[] args = extractFunctionArgs(condition);
1225	            if (args.length == 2) {
1226	                String attrName = resolveAttributeName(args[0], exprAttrNames);
1227	                String prefix = resolveExprValue(args[1], exprAttrValues);
1228	                String actual = item != null ? extractScalarValue(item.get(attrName)) : null;
1229	                return actual != null && prefix != null && actual.startsWith(prefix);
1230	            }
1231	            return false;
1232	        }
1233	        if (condLower.startsWith("contains")) {
1234	            String[] args = extractFunctionArgs(condition);
1235	            if (args.length == 2) {
1236	                String attrName = resolveAttributeName(args[0], exprAttrNames);
1237	                if (item == null) return false;
1238	                JsonNode attrNode = item.get(attrName);
1239	                if (attrNode == null) return false;
1240	                // Resolve the raw AttributeValue node for type-aware comparisons
1241	                JsonNode searchAttrValue = exprAttrValues != null
1242	                        ? exprAttrValues.get(args[1].trim()) : null;
1243	                if (searchAttrValue == null) return false;
1244	                // List type: type-aware element membership check
1245	                if (attrNode.has("L")) {
1246	                    for (JsonNode element : attrNode.get("L")) {
1247	                        if (attributeValuesEqual(element, searchAttrValue)) return true;
1248	                    }
1249	                    return false;
1250	                }
1251	                // SS (String Set): operand must be S type
1252	                if (attrNode.has("SS")) {
1253	                    if (!searchAttrValue.has("S")) return false;
1254	                    String target = searchAttrValue.get("S").asText();
1255	                    for (JsonNode element : attrNode.get("SS")) {
1256	                        if (target.equals(element.asText())) return true;
1257	                    }
1258	                    return false;
1259	                }
1260	                // NS (Number Set): operand must be N type, compare numerically
1261	                if (attrNode.has("NS")) {
1262	                    if (!searchAttrValue.has("N")) return false;
1263	                    try {
1264	                        java.math.BigDecimal target = new java.math.BigDecimal(searchAttrValue.get("N").asText());
1265	                        for (JsonNode element : attrNode.get("NS")) {
1266	                            if (target.compareTo(new java.math.BigDecimal(element.asText())) == 0) return true;
1267	                        }
1268	                    } catch (NumberFormatException ignored) {}
1269	                    return false;
1270	                }
1271	                // BS (Binary Set): operand must be B type
1272	                if (attrNode.has("BS")) {
1273	                    if (!searchAttrValue.has("B")) return false;
1274	                    String target = searchAttrValue.get("B").asText();
1275	                    for (JsonNode element : attrNode.get("BS")) {
1276	                        if (target.equals(element.asText())) return true;
1277	                    }
1278	                    return false;
1279	                }
1280	                // String type: operand must be S type, check substring
1281	                if (attrNode.has("S") && searchAttrValue.has("S")) {
1282	                    return attrNode.get("S").asText().contains(searchAttrValue.get("S").asText());
1283	                }
1284	                return false;
1285	            }
1286	            return false;
1287	        }
1288	
1289	        // Comparison operators: =, <>, <, <=, >, >=
1290	        String[] operators = {"<>", "<=", ">=", "=", "<", ">"};
1291	        for (String op : operators) {
1292	            int opIdx = condition.indexOf(op);
1293	            if (opIdx > 0) {
1294	                String left = condition.substring(0, opIdx).trim();
1295	                String right = condition.substring(opIdx + op.length()).trim();
1296	
1297	                String attrName = resolveAttributeName(left, exprAttrNames);
1298	                String expected = resolveExprValue(right, exprAttrValues);
1299	                String actual = item != null ? extractScalarValue(item.get(attrName)) : null;
1300	
1301	                if (actual == null || expected == null) return false;
1302	
1303	                return switch (op) {
1304	                    case "=" -> actual.equals(expected);
1305	                    case "<>" -> !actual.equals(expected);
1306	                    case "<" -> compareValues(actual, expected) < 0;
1307	                    case "<=" -> compareValues(actual, expected) <= 0;
1308	                    case ">" -> compareValues(actual, expected) > 0;
1309	                    case ">=" -> compareValues(actual, expected) >= 0;
1310	                    default -> false;
1311	                };
1312	            }
1313	        }
1314	
1315	        return true; // Unknown condition — pass through
1316	    }
