1318	    private String resolveExprValue(String placeholder, JsonNode exprAttrValues) {
1319	        placeholder = trimBalancedOuterParens(placeholder).trim();
1320	        if (placeholder.startsWith(":") && exprAttrValues != null) {
1321	            return extractScalarValue(exprAttrValues.get(placeholder));
1322	        }
1323	        return placeholder;
1324	    }
