1326	    private boolean attributeValuesEqual(JsonNode a, JsonNode b) {
1327	        if (a == null || b == null) return a == b;
1328	        // Scalar types: S, B, BOOL, NULL
1329	        for (String type : new String[]{"S", "B", "BOOL", "NULL"}) {
1330	            if (a.has(type) && b.has(type)) {
1331	                return a.get(type).asText().equals(b.get(type).asText());
1332	            }
1333	            if (a.has(type) || b.has(type)) return false; // type mismatch
1334	        }
1335	        // Numeric comparison with normalization
1336	        if (a.has("N") && b.has("N")) {
1337	            try {
1338	                return new java.math.BigDecimal(a.get("N").asText())
1339	                        .compareTo(new java.math.BigDecimal(b.get("N").asText())) == 0;
1340	            } catch (NumberFormatException e) {
1341	                return false;
1342	            }
1343	        }
1344	        if (a.has("N") || b.has("N")) return false;
1345	        // Map type: compare all entries recursively
1346	        if (a.has("M") && b.has("M")) {
1347	            JsonNode aMap = a.get("M");
1348	            JsonNode bMap = b.get("M");
1349	            if (aMap.size() != bMap.size()) return false;
1350	            var fields = aMap.fields();
1351	            while (fields.hasNext()) {
1352	                var entry = fields.next();
1353	                if (!bMap.has(entry.getKey())) return false;
1354	                if (!attributeValuesEqual(entry.getValue(), bMap.get(entry.getKey()))) return false;
1355	            }
1356	            return true;
1357	        }
1358	        // List type: compare element by element
1359	        if (a.has("L") && b.has("L")) {
1360	            JsonNode aList = a.get("L");
1361	            JsonNode bList = b.get("L");
1362	            if (aList.size() != bList.size()) return false;
1363	            for (int i = 0; i < aList.size(); i++) {
1364	                if (!attributeValuesEqual(aList.get(i), bList.get(i))) return false;
1365	            }
1366	            return true;
1367	        }
1368	        // Different types are never equal
1369	        return false;
1370	    }
1371	
1372	    private int compareValues(String a, String b) {
1373	        // Try numeric comparison first
1374	        try {
1375	            return Double.compare(Double.parseDouble(a), Double.parseDouble(b));
1376	        } catch (NumberFormatException e) {
1377	            return a.compareTo(b);
1378	        }
1379	    }
1380	
1381	    private static final String DOT_ESCAPE = "\uFF0E";
1382	
1383	    private String resolveAttributePath(String path, JsonNode exprAttrNames) {
1384	        // Resolve each segment of a dotted path, e.g. "passengerInformation.#name"
1385	        // ExpressionAttributeNames may resolve to names containing dots (e.g. "#a" -> "foo.bar").
1386	        // Escape those dots so resolveNestedAttribute treats them as single keys.
1387	        String[] segments = path.split("\\.");
1388	        StringBuilder resolved = new StringBuilder();
1389	        for (int i = 0; i < segments.length; i++) {
1390	            if (i > 0) resolved.append(".");
1391	            String original = segments[i];
1392	            String resolvedSegment = resolveAttributeName(original, exprAttrNames);
1393	            if (original.startsWith("#") && resolvedSegment != null) {
1394	                resolvedSegment = resolvedSegment.replace(".", DOT_ESCAPE);
1395	            }
1396	            resolved.append(resolvedSegment);
1397	        }
1398	        return resolved.toString();
1399	    }
1400	
1401	    private JsonNode resolveNestedAttribute(JsonNode item, String path) {
1402	        // Navigate a dotted path through DynamoDB's {"M": {...}} structure
1403	        String[] segments = path.split("\\.");
1404	        JsonNode current = item;
1405	        for (int i = 0; i < segments.length; i++) {
1406	            if (current == null) return null;
1407	            String segment = segments[i].replace(DOT_ESCAPE, ".");
1408	            if (i == 0) {
1409	                // First segment: resolve against the top-level item map
1410	                current = current.get(segment);
1411	            } else {
1412	                // Subsequent segments: descend into DynamoDB Map type
1413	                if (current.has("M")) {
1414	                    current = current.get("M").get(segment);
1415	                } else {
1416	                    current = current.get(segment);
1417	                }
1418	            }
1419	        }
1420	        return current;
1421	    }
1422	
1423	    private String extractFunctionArg(String funcCall) {
1424	        int open = funcCall.indexOf('(');
1425	        int close = funcCall.lastIndexOf(')');
1426	        if (open >= 0 && close > open) {
1427	            return funcCall.substring(open + 1, close).trim();
1428	        }
1429	        return funcCall;
1430	    }
1431	
1432	    private String[] extractFunctionArgs(String funcCall) {
1433	        int open = funcCall.indexOf('(');
1434	        int close = funcCall.lastIndexOf(')');
1435	        if (open >= 0 && close > open) {
1436	            String inner = funcCall.substring(open + 1, close);
1437	            String[] args = inner.split(",", 2);
1438	            for (int i = 0; i < args.length; i++) {
1439	                args[i] = args[i].trim();
1440	            }
1441	            return args;
1442	        }
1443	        return new String[]{funcCall};
1444	    }
1445	
1446	    // --- Helper methods ---
1447	
1448	    private static String regionKey(String region, String tableName) {
1449	        return region + "::" + tableName;
1450	    }
1451	
1452	    String buildItemKey(TableDefinition table, JsonNode item) {
1453	        String pkName = table.getPartitionKeyName();
1454	        JsonNode pkAttr = item.get(pkName);
1455	        if (pkAttr == null) {
1456	            throw new AwsException("ValidationException",
1457	                    "One of the required keys was not given a value", 400);
1458	        }
1459	
1460	        String pk = extractScalarValue(pkAttr);
1461	        String skName = table.getSortKeyName();
1462	        if (skName != null) {
1463	            JsonNode skAttr = item.get(skName);
1464	            if (skAttr != null) {
1465	                return pk + "#" + extractScalarValue(skAttr);
1466	            }
1467	        }
1468	        return pk;
1469	    }
1470	
1471	    private String buildItemKeyFromNode(JsonNode item, String pkName, String skName) {
1472	        JsonNode pkAttr = item.get(pkName);
1473	        if (pkAttr == null) return "";
1474	        String pk = extractScalarValue(pkAttr);
1475	        if (skName != null) {
1476	            JsonNode skAttr = item.get(skName);
1477	            if (skAttr != null) {
1478	                return pk + "#" + extractScalarValue(skAttr);
1479	            }
1480	        }
1481	        return pk != null ? pk : "";
1482	    }
1483	
1484	    JsonNode buildKeyNode(TableDefinition table, JsonNode item, String pkName, String skName) {
1485	        com.fasterxml.jackson.databind.node.ObjectNode keyNode =
1486	                com.fasterxml.jackson.databind.node.JsonNodeFactory.instance.objectNode();
1487	        JsonNode pkAttr = item.get(pkName);
1488	        if (pkAttr != null) {
1489	            keyNode.set(pkName, pkAttr);
1490	        }
1491	        if (skName != null) {
1492	            JsonNode skAttr = item.get(skName);
1493	            if (skAttr != null) {
1494	                keyNode.set(skName, skAttr);
1495	            }
1496	        }
1497	        return keyNode;
1498	    }
1499	
1500	    private String extractScalarValue(JsonNode attrValue) {
1501	        if (attrValue == null) return null;
1502	        if (attrValue.has("S")) return attrValue.get("S").asText();
1503	        if (attrValue.has("N")) return attrValue.get("N").asText();
1504	        if (attrValue.has("B")) return attrValue.get("B").asText();
1505	        if (attrValue.has("BOOL")) return attrValue.get("BOOL").asText();
1506	        return attrValue.asText();
1507	    }
1508	
1509	    private boolean matchesAttributeValue(JsonNode attrValue, String expected) {
1510	        if (attrValue == null || expected == null) return false;
1511	        String actual = extractScalarValue(attrValue);
1512	        return expected.equals(actual);
1513	    }
1514	
1515	    private String extractComparisonValue(JsonNode condition) {
1516	        if (condition == null) return null;
1517	        JsonNode attrValueList = condition.get("AttributeValueList");
1518	        if (attrValueList != null && attrValueList.isArray() && !attrValueList.isEmpty()) {
1519	            return extractScalarValue(attrValueList.get(0));
1520	        }
1521	        return null;
1522	    }
1523	
1524	    // NE, CONTAINS, NOT_CONTAINS, IN, NULL, NOT_NULL not yet supported
1525	    private boolean matchesKeyCondition(JsonNode attrValue, JsonNode condition) {
1526	        if (condition == null) return true;
1527	        String op = condition.has("ComparisonOperator") ? condition.get("ComparisonOperator").asText() : "EQ";
1528	        String compareValue = extractComparisonValue(condition);
1529	        String actual = extractScalarValue(attrValue);
1530	        if (actual == null) return false;
1531	
1532	        return switch (op) {
1533	            case "EQ" -> actual.equals(compareValue);
1534	            case "BEGINS_WITH" -> actual.startsWith(compareValue);
1535	            case "GT" -> actual.compareTo(compareValue) > 0;
1536	            case "GE" -> actual.compareTo(compareValue) >= 0;
1537	            case "LT" -> actual.compareTo(compareValue) < 0;
1538	            case "LE" -> actual.compareTo(compareValue) <= 0;
1539	            case "BETWEEN" -> {
1540	                JsonNode list = condition.get("AttributeValueList");
1541	                if (list.size() >= 2) {
1542	                    String low = extractScalarValue(list.get(0));
1543	                    String high = extractScalarValue(list.get(1));
1544	                    yield actual.compareTo(low) >= 0 && actual.compareTo(high) <= 0;
1545	                }
1546	                yield false;
1547	            }
1548	            default -> true;
1549	        };
1550	    }
1551	
1552	    private List<JsonNode> queryWithExpression(ConcurrentSkipListMap<String, JsonNode> items,
1553	                                                String pkName, String skName,
1554	                                                String expression,
1555	                                                JsonNode expressionAttrValues,
1556	                                                JsonNode exprAttrNames) {
1557	        expression = trimBalancedOuterParens(expression);
1558	        List<JsonNode> results = new ArrayList<>();
1559	
1560	        // Parse simple expressions: "pk = :val" or "pk = :val AND sk begins_with :prefix"
1561	        String[] parts = expression.split("\\s+[Aa][Nn][Dd]\\s+", 2);
1562	        String pkExpression = trimBalancedOuterParens(parts[0].trim());
1563	        String skExpression = parts.length > 1 ? trimBalancedOuterParens(parts[1].trim()) : null;
1564	
1565	        // Extract pk attr name from expression (may use #alias)
1566	        String pkAttrInExpr = pkExpression.split("\\s*=\\s*")[0].trim();
1567	        String resolvedPkName = resolveAttributeName(pkAttrInExpr, exprAttrNames);
1568	
1569	        // Extract pk value
1570	        String pkPlaceholder = extractPlaceholder(pkExpression);
1571	        String pkValue = pkPlaceholder != null && expressionAttrValues != null
1572	                ? extractScalarValue(expressionAttrValues.get(pkPlaceholder))
1573	                : null;
1574	
1575	        for (JsonNode item : items.values()) {
1576	            if (!item.has(resolvedPkName)) continue;
1577	            if (pkValue != null && !matchesAttributeValue(item.get(resolvedPkName), pkValue)) {
1578	                continue;
1579	            }
1580	
1581	            if (skExpression != null && skName != null) {
1582	                if (!matchesSkExpression(item.get(skName), skExpression, expressionAttrValues)) {
1583	                    continue;
1584	                }
1585	            }
1586	
1587	            results.add(item);
1588	        }
1589	
1590	        return results;
1591	    }
1592	
1593	    private boolean matchesSkExpression(JsonNode skValue, String expression, JsonNode exprValues) {
1594	        expression = trimBalancedOuterParens(expression);
1595	        String actual = extractScalarValue(skValue);
1596	        if (actual == null) return false;
1597	
1598	        String exprLower = expression.toLowerCase();
1599	        if (exprLower.contains("begins_with")) {
1600	            String placeholder = extractPlaceholder(expression);
1601	            String prefix = placeholder != null && exprValues != null
1602	                    ? extractScalarValue(exprValues.get(placeholder)) : null;
1603	            return prefix != null && actual.startsWith(prefix);
1604	        }
1605	
1606	        if (exprLower.contains(" between ")) {
1607	            int betweenIdx = exprLower.indexOf(" between ");
1608	            int andIdx = exprLower.indexOf(" and ", betweenIdx + " between ".length());
1609	            if (andIdx < 0) return false;
1610	
1611	            String lowerExpr = expression.substring(betweenIdx + " between ".length(), andIdx).trim();
1612	            String upperExpr = expression.substring(andIdx + " and ".length()).trim();
1613	            String lowerPlaceholder = lowerExpr.startsWith(":") ? lowerExpr.split("\\s+")[0] : null;
1614	            String upperPlaceholder = upperExpr.startsWith(":") ? upperExpr.split("\\s+")[0] : null;
1615	            String lower = lowerPlaceholder != null && exprValues != null
1616	                    ? extractScalarValue(exprValues.get(lowerPlaceholder)) : null;
1617	            String upper = upperPlaceholder != null && exprValues != null
1618	                    ? extractScalarValue(exprValues.get(upperPlaceholder)) : null;
1619	            if (lower == null || upper == null) return false;
1620	            return compareValues(actual, lower) >= 0 && compareValues(actual, upper) <= 0;
1621	        }
1622	
1623	        // Detect comparison operator
1624	        String[] operators = {"<>", "<=", ">=", "=", "<", ">"};
1625	        for (String op : operators) {
1626	            int opIdx = expression.indexOf(op);
1627	            if (opIdx > 0) {
1628	                String right = expression.substring(opIdx + op.length()).trim();
1629	                String placeholder = right.startsWith(":") ? right.split("\\s+")[0] : null;
1630	                String expected = placeholder != null && exprValues != null
1631	                        ? extractScalarValue(exprValues.get(placeholder)) : null;
1632	                if (expected == null) return false;
1633	                return switch (op) {
1634	                    case "=" -> actual.equals(expected);
1635	                    case "<>" -> !actual.equals(expected);
1636	                    case ">=" -> actual.compareTo(expected) >= 0;
1637	                    case "<=" -> actual.compareTo(expected) <= 0;
1638	                    case ">" -> actual.compareTo(expected) > 0;
1639	                    case "<" -> actual.compareTo(expected) < 0;
1640	                    default -> true;
1641	                };
1642	            }
1643	        }
1644	        return true;
1645	    }
1646	
1647	    private String extractPlaceholder(String expression) {
1648	        // Find :placeholder in expression
1649	        int idx = expression.indexOf(':');
1650	        if (idx < 0) return null;
1651	        int end = idx + 1;
1652	        while (end < expression.length() && (Character.isLetterOrDigit(expression.charAt(end)) || expression.charAt(end) == '_')) {
1653	            end++;
1654	        }
1655	        return expression.substring(idx, end);
1656	    }
1657	
1658	    private String trimBalancedOuterParens(String expression) {
1659	        if (expression == null) return null;
1660	        String trimmed = expression.trim();
1661	        while (trimmed.length() >= 2 && trimmed.startsWith("(") && trimmed.endsWith(")")
1662	                && hasBalancedOuterParens(trimmed)) {
1663	            trimmed = trimmed.substring(1, trimmed.length() - 1).trim();
1664	        }
1665	        return trimmed;
1666	    }
1667	
1668	    private boolean hasBalancedOuterParens(String expression) {
1669	        int depth = 0;
1670	        for (int i = 0; i < expression.length(); i++) {
1671	            char c = expression.charAt(i);
1672	            if (c == '(') {
1673	                depth++;
1674	            } else if (c == ')') {
1675	                depth--;
1676	                if (depth == 0 && i < expression.length() - 1) {
1677	                    return false;
1678	                }
1679	                if (depth < 0) {
1680	                    return false;
1681	                }
1682	            }
1683	        }
1684	        return depth == 0;
1685	    }
1686	
1687	    private AwsException resourceNotFoundException(String tableName) {
1688	        return new AwsException("ResourceNotFoundException",
1689	                "Requested resource not found: Table: " + tableName + " not found", 400);
1690	    }
1691	
1692	    public record UpdateResult(JsonNode newItem, JsonNode oldItem) {}
1693	    public record ScanResult(List<JsonNode> items, int scannedCount, JsonNode lastEvaluatedKey) {}
1694	    public record QueryResult(List<JsonNode> items, int scannedCount, JsonNode lastEvaluatedKey) {}
1695	}
