    @Test
    void updateItemSetWithRemoveCombined() {
        // Reproduces bug: SET #entries = :entries, #isActive = :isActive REMOVE #tempField, #created
        // where the last SET attribute was not set because findNextComma found a comma
        // inside the REMOVE clause instead of stopping at the clause boundary.
        createUsersTable();
        service.putItem("Users", item("userId", "user-1", "entries", "initial", "tempField", "temp"));

        ObjectNode key = item("userId", "user-1");

        ObjectNode exprNames = mapper.createObjectNode();
        exprNames.put("#entries", "entries");
        exprNames.put("#isActive", "isActive");
        exprNames.put("#tempField", "tempField");
        exprNames.put("#created", "created");

        ObjectNode exprValues = mapper.createObjectNode();
        exprValues.set(":entries", attributeValue("S", "updated entries"));
        exprValues.set(":isActive", attributeValue("BOOL", "true"));

        DynamoDbService.UpdateResult result = service.updateItem("Users", key, null,
                "SET #entries = :entries, #isActive = :isActive REMOVE #tempField, #created",
                exprNames, exprValues, null);

        JsonNode stored = service.getItem("Users", key);
        assertNotNull(stored);
        assertEquals("updated entries", stored.get("entries").get("S").asText(),
                "entries should be updated");
        assertTrue(stored.get("isActive").get("BOOL").asBoolean(),
                "isActive should be true - this is the core bug fix");
        assertNull(stored.get("tempField"), "tempField should be removed");
    }

